export default function PayNextPanel() {
  const [phase, setPhase] = useState("idle");
  const [payments, setPayments] = useState([]);
  const [accounts, setAccounts] = useState([]);
  const [error, setError] = useState(null);

  useEffect(() => {
    tools.host_listScheduledPayments({}).then((r) => setPayments(r.data || []));
    tools.host_listAccounts({}).then((r) => setAccounts(r.data || []));
  }, []);

  const next = payments[0];
  const checking = accounts.find((a) => a.type === "checking" || (a.name && a.name.toLowerCase().includes("checking")));

  const pay = async () => {
    if (!next) return;
    setPhase("sending");
    setError(null);
    try {
      const result = await tools.host_transferMoney({
        amount: next.amountCents,
        recipient_name: next.payeeName,
        memo: next.description || next.payeeName,
      });
      setPhase(result && result.status === "pending-approval" ? "awaiting" : "done");
    } catch (e) {
      setError("Something went wrong. Please try again.");
      setPhase("idle");
    }
  };

  if (!next) return (
    <div style={{ padding: 20, background: "var(--vendo-color-surface)", border: "1px solid var(--vendo-color-border)", borderRadius: "var(--vendo-radius-medium)", color: "var(--vendo-color-muted)", fontFamily: "var(--vendo-font-family)" }}>
      No upcoming scheduled payments found.
    </div>
  );

  return (
    <div style={{ padding: 20, background: "var(--vendo-color-surface)", border: "1px solid var(--vendo-color-border)", borderRadius: "var(--vendo-radius-medium)", fontFamily: "var(--vendo-font-family)", display: "grid", gap: 16 }}>
      <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
        <span style={{ fontSize: 13, color: "var(--vendo-color-muted)" }}>Paying next</span>
        <span style={{ fontSize: 20, fontWeight: 600, color: "var(--vendo-color-text)" }}>{next.payeeName}</span>
        <span style={{ fontSize: 15, color: "var(--vendo-color-text)" }}>{fmt.money(next.amountCents)} &mdash; due {fmt.dateTime(next.dueDate)}</span>
      </div>
      {checking && (
        <div style={{ fontSize: 13, color: "var(--vendo-color-muted)" }}>
          From: <strong style={{ color: "var(--vendo-color-text)" }}>{checking.name}</strong> &nbsp;·&nbsp; Balance: {fmt.money(checking.balanceCents)}
        </div>
      )}
      {error && (
        <div style={{ fontSize: 13, color: "var(--vendo-color-danger)" }}>{error}</div>
      )}
      {phase === "awaiting" && (
        <div style={{ padding: "10px 14px", background: "#FBFBFA", border: "1px solid var(--vendo-color-border)", borderRadius: "var(--vendo-radius-small)", fontSize: 14, color: "var(--vendo-color-muted)" }}>
          ⏳ Awaiting your approval to complete this payment…
        </div>
      )}
      {phase === "done" && (
        <div style={{ padding: "10px 14px", background: "#FBFBFA", border: "1px solid var(--vendo-color-border)", borderRadius: "var(--vendo-radius-small)", fontSize: 14, color: "var(--vendo-color-text)" }}>
          ✓ Payment sent successfully.
        </div>
      )}
      {(phase === "idle" || phase === "sending") && (
        <button
          onClick={pay}
          disabled={phase === "sending"}
          style={{
            padding: "10px 18px",
            background: "var(--vendo-color-accent)",
            color: "var(--vendo-color-accent-text)",
            border: "none",
            borderRadius: "var(--vendo-radius-small)",
            fontFamily: "var(--vendo-font-family)",
            fontSize: 15,
            fontWeight: 600,
            cursor: phase === "sending" ? "not-allowed" : "pointer",
            opacity: phase === "sending" ? 0.6 : 1,
          }}
        >
          {phase === "sending" ? "Sending…" : `Pay ${fmt.money(next.amountCents)} now`}
        </button>
      )}
    </div>
  );
}
